                          if (highestOpenAccounts >= 9) return '5/10';
                          if (highestOpenAccounts >= 8) return '4/10';
                          if (highestOpenAccounts >= 7) return '3/10';
                          if (highestOpenAccounts >= 6) return '2/10';
                          if (highestOpenAccounts >= 5) return '1/10';
